// Classic hello world
console.log('Hello from the extension!');

// Math
const pi = Math.PI;
const r = 10;
const area = pi * r * r;
console.log(`Circle area (r=${r}): ${area.toFixed(2)}`);

// Arrays
const nums = [1, 2, 3, 4, 5];
const doubled = nums.map(n => n * 2);
console.log('Doubled:', doubled);

// Objects
const user = { name: 'Extension User', level: 42 };
console.log(`User: ${user.name} (level ${user.level})`);

// Sleep with countdown
for (let i = 3; i > 0; i--) {
  console.log(`Sleeping... ${i}`);
  await web.sleep(300);
}
console.log('Awake!');

// Parallel sleeps
console.log('Starting parallel timers...');
const t1 = web.sleep(200).then(() => 'Timer A done');
const t2 = web.sleep(400).then(() => 'Timer B done');
const t3 = web.sleep(600).then(() => 'Timer C done');
const results = await Promise.all([t1, t2, t3]);
results.forEach(r => console.log(r));

// Fetch from httpbin (a request echo service)
const url = 'https://httpbin.org/get';
console.log(`Fetching: ${url}`);

try {
  const result = await web.fetch(url);
  console.log('Status:', result.status);

  const body = JSON.parse(result.body);
  console.log('Your IP:', body.origin);
  console.log('User-Agent:', body.headers['User-Agent']?.slice(0, 50));
  console.log('URL args:', JSON.stringify(body.args));
} catch (err) {
  console.log('Error:', err.message);
}

// Try a POST request
console.log('\n--- POST request ---');
try {
  const postResult = await web.fetch({
    url: 'https://httpbin.org/post',
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ hello: 'from extension', timestamp: Date.now() })
  });
  const postBody = JSON.parse(postResult.body);
  console.log('Posted data echoed back:', JSON.stringify(postBody.json, null, 2));
} catch (err) {
  console.log('POST error:', err.message);
}

// List all tabs
const allTabs = await chrome.tabs.query({});
console.log(`You have ${allTabs.length} tab(s) open`);

allTabs.slice(0, 8).forEach((tab, i) => {
  const title = (tab.title || 'Untitled').slice(0, 40);
  const url = (tab.url || '').slice(0, 50);
  const active = tab.active ? '★' : ' ';
  console.log(`${active} [${tab.id}] ${title}`);
  console.log(`     ${url}`);
});

// Get active tab details
const active = await chrome.tabs.query({ active: true, currentWindow: true });
if (active[0]) {
  console.log('\nActive tab:', active[0].id, active[0].url);
}

// Count by window
const windows = {};
allTabs.forEach(t => {
  windows[t.windowId] = (windows[t.windowId] || 0) + 1;
});
console.log('\nTabs per window:', windows);

// Get current page info
const url = await page.url();
const title = await page.title();
console.log('Current page:');
console.log('  URL:', url);
console.log('  Title:', title);

// Take a snapshot (accessible tree view)
const snap = await page.snapshot();
console.log('\nPage snapshot (first 800 chars):');
console.log(snap.slice(0, 800));

// Scroll down a bit
await page.scroll('down', 300);
console.log('\nScrolled down 300px');

// Scroll back up
await page.scroll('up', 300);
console.log('Scrolled back up');

// web.storage (localStorage - notebook scoped)
await web.storage.set('player_name', 'Extension Hero');
await web.storage.set('score', '1337');
await web.storage.set('level', '5');

const name = await web.storage.get('player_name');
const keys = await web.storage.list();
console.log('web.storage keys:', keys);
console.log('Player:', name);

// chrome.storage.local (extension-wide, survives restart!)
await chrome.storage.local.set({
  high_score: 9999,
  achievements: ['First Run', 'Tab Master', 'Fetch Hero'],
  last_played: new Date().toISOString()
});

const saved = await chrome.storage.local.get(['high_score', 'achievements']);
console.log('\nchrome.storage.local:');
console.log('  High score:', saved.high_score);
console.log('  Achievements:', saved.achievements?.join(', '));

// Write to clipboard
const secretMessage = 'The extension can write to your clipboard!';
await web.clipboard.write(secretMessage);
console.log('Wrote to clipboard:', secretMessage);

// Read it back
const readBack = await web.clipboard.read();
console.log('Read from clipboard:', readBack);

// Verify match
console.log('Match:', readBack === secretMessage ? '✅ Yes!' : '❌ No');

const message = 'Hello, Extension World!';

// SHA-256
console.log('SHA-256:', crypto.sha256(message));

// MD5
console.log('MD5:', crypto.md5(message));

// HMAC-SHA256
console.log('HMAC:', crypto.hmac_sha256('my-secret-key', message));

// Hex encode/decode
const hex = crypto.hex_encode(message);
console.log('\nHex encoded:', hex);
console.log('Decoded:', crypto.hex_decode(hex));

// Try hashing a URL
const url = await page.url();
console.log('\nHash of current URL:');
console.log('  SHA-256:', crypto.sha256(url));
console.log('  MD5:', crypto.md5(url));

// Create a directory
await fs.mkdir('/tmp/playground');

// Write a file
const poem = `Roses are red,
Violets are blue,
The extension is cool,
And so are you.`;
await fs.write_text('/tmp/playground/poem.txt', poem);
console.log('Wrote poem.txt');

// Read it back
const content = await fs.read_text('/tmp/playground/poem.txt');
console.log('\nContents:');
console.log(content);

// List directory
const files = await fs.list('/tmp/playground');
console.log('\nFiles:', files);

// Write JSON
const data = { name: 'playground', items: [1, 2, 3], active: true };
await fs.write_text('/tmp/playground/data.json', JSON.stringify(data, null, 2));
const jsonBack = await fs.read_text('/tmp/playground/data.json');
console.log('\nJSON back:', JSON.parse(jsonBack));

// Bookmarks
try {
  const bookmarks = await chrome.bookmarks.search({ query: '' });
  console.log(`Found ${bookmarks.length} bookmark(s)`);
  bookmarks.slice(0, 5).forEach(b => {
    console.log(`  📌 ${b.title?.slice(0, 40)}`);
  });
} catch (e) {
  console.log('Bookmarks:', e.message);
}

// History (recent)
try {
  const history = await chrome.history.search({ text: '', maxResults: 5 });
  console.log('\nRecent history:');
  history.forEach(h => {
    const title = h.title?.slice(0, 35) || 'Untitled';
    console.log(`  🕐 ${title}`);
  });
} catch (e) {
  console.log('History:', e.message);
}

// Cookies for current site
try {
  const currentUrl = await page.url();
  const cookies = await chrome.cookies.getAll({ url: currentUrl });
  console.log(`\nCookies for current site (${cookies.length}):`);
  cookies.forEach(c => {
    console.log(`  🍪 ${c.name}=${c.value.slice(0, 30)}`);
  });
} catch (e) {
  console.log('Cookies:', e.message);
}

// Check current URL
const before = await page.url();
console.log('Current URL:', before);

// Navigate to example.comg
console.log('Navigating to example.com...');
await page.goto('https://example.com');
await web.sleep(1000);
const after = await page.title();
console.log('New page title:', after);

// Go back
console.log('Going back...');
await page.back();
await web.sleep(500);
const back = await page.url();
console.log('After back:', back);

// Inspect all globals
const globals = runtime.inspect();
console.log(`Total globals: ${globals.length}`);

// Group by type
const byType = {};
globals.forEach(g => {
  byType[g.type] = (byType[g.type] || 0) + 1;
});
console.log('\nBy type:', byType);

// Show all API namespaces
const namespaces = globals
  .filter(g => g.type === 'object' && g.keys && g.keys.length > 0)
  .map(g => g.name)
  .sort();
console.log('\nNamespaces:', namespaces.join(', '));

// Show web.* APIs
const webObj = globals.find(g => g.name === 'web');
if (webObj?.keys) {
  console.log('\nweb.* APIs:', webObj.keys.sort().join(', '));
}

// Show chrome.* APIs
const chromeObj = globals.find(g => g.name === 'chrome');
if (chromeObj?.keys) {
  console.log('\nchrome.* APIs:', chromeObj.keys.sort().join(', '));
}

